INSERT INTO `email_templates` (`id`, `date_entered`, `date_modified`, `modified_user_id`, `created_by`, `published`, `name`, `description`, `subject`, `body`, `body_html`, `deleted`, `assigned_user_id`, `text_only`, `type`) VALUES
('d3b49c38-eeba-b910-2590-5b4069caaac1', NOW(), NOW(), '1', '1', NULL, 'Exemple - Donació', 'Exemple de plantilla de correu electrònic per confirmar i agrair una donació', 'Gràcies per la teva donació!', 'Benvolgut/da $contact_first_name $contact_last_name:\r\n\r\nHem rebut la teva donació de $stic_payments_amount €.\r\n\r\nMoltes gràcies pel teu suport!\r\n\r\n', '<p>Benvolgut/da $contact_first_name $contact_last_name:</p>\n<p>Hem rebut la teva donació de $stic_payments_amount €.</p>\n<p>Moltes gràcies pel teu suport!</p>', 0, '1', 0, 'email'),
('dba65685-d26f-6ecd-802c-5b406983c9b5', NOW(), NOW(), '1', '1', NULL, 'Exemple - Inscripció', 'Exemple de plantilla de correu electrònic per confirmar la inscripció a un esdeveniment', '$stic_events_name: Inscripció confirmada', 'Benvolgut/da $contact_first_name $contact_last_name:\r\n\r\nHem rebut la teva inscripció a $stic_events_name.\r\n\r\nA dia $stic_registrations_registration_date la teva inscripció consta com a $stic_registrations_status.\r\n\r\nEns veiem el $stic_events_start_date!', '<p>Benvolgut/da $contact_first_name $contact_last_name:</p>\n<p>Hem rebut la teva inscripció a $stic_events_name.</p>\n<p>A dia $stic_registrations_registration_date la teva tu inscripció consta com a $stic_registrations_status.</p>\n<p>Ens veiem el $stic_events_start_date!</p>', 0, '1', 0, 'email'),
('52cdc554-bd90-f8f9-e2e0-66d718ae8fe9', NOW(), NOW(), '1', '1', NULL, 'Exemple - Nova subvenció', 'Exemple de plantilla de correu electrònic per notificar la convocatòria d''una nova subvenció', 'Nova convocatòria de subvenció: $opportunity_name', 'Nova convocatòria de subvenció: $opportunity_name\r\n\r\n$opportunity_stic_additional_information_c\r\nPodeu trobar més informació a: $opportunity_stic_opportunity_url_c', '<p>Nova convocatòria de subvenció: $opportunity_name</p><p></p><p>$opportunity_stic_additional_information_c</p><p>Podeu trobar més informació a: $opportunity_stic_opportunity_url_c</p>', 0, '1', 0, 'notification'),
('9f118e85-13f2-baa9-4ee3-66d80c674dea', NOW(), NOW(), '1', '1', NULL, 'Exemple - Nou esdeveniment', 'Exemple de plantilla de correu electrònic per notificar un nou esdeveniment', 'Nou esdeveniment: $stic_events_name', '$stic_events_name\r\n\r\nData d''inici: $stic_events_start_date\r\nData de finalització: $stic_events_end_date\r\nUbicació: $stic_events_stic_events_fp_event_locations_name', '<p>$stic_events_name</p><p></p><p>Data d''inici: $stic_events_start_date</p><p>Data de finalització: $stic_events_end_date</p><p>Ubicació: $stic_events_stic_events_fp_event_locations_name</p>', 0, '1', 0, 'notification'),
('000005f1-2e4e-3b11-051f-68e3c9e70330', NOW(), NOW(), '1', '1', 'off', 'Exemple - Sol·licitud de firma', 'Plantilla per notificar al firmant que s''ha sol·licitat la seva firma en un document.', '[Firma de document] Sol·licitud de firma: $stic_signatures_pdf_template', 'Sol·licitud de firma\n\nS''ha sol·licitat la vostra firma al següent document:\n\n$stic_signatures_pdf_template\n\nFirmant: $contact_full_name$contact_user_full_name\nData de caducitat: $stic_signatures_expiration_date\n\nPer firmar el document, feu clic a continuació i se us redirigirà al portal de firma segura.\n\nFirmar el document: $sugarurl/index.php?entryPoint=sticSign&signatureId=$stic_signatures_id&targetId=$contact_id$contact_user_id\n\nSi no podeu accedir al portal de firma, copieu i enganxeu l''enllaç al vostre navegador:\n$sugarurl/index.php?entryPoint=sticSign&signatureId=$stic_signatures_id&targetId=$contact_id$contact_user_id', '<!DOCTYPE html>\n<html>\n<head>\n</head>\n<body>\n<p> </p>\n<div style="max-width: 600px; margin: 20px auto; background-color: #ffffff; border-radius: 8px; box-shadow: 0 4px 8px rgba(0,0,0,0.1); overflow: hidden;">\n<div style="background-color: #b5bc31; color: #000000; padding: 20px; text-align: center;">\n<h1 style="margin: 0; font-size: 24px;">Firma de document</h1>\n</div>\n<div style="padding: 20px;">\n<p style="font-size: 16px; color: #555555;">S''ha sol·licitat la vostra firma al següent document:</p>\n<div style="background-color: #f9f9f9; padding: 15px; border-radius: 6px; border: 1px solid #eeeeee; margin-top: 20px;">\n<p style="margin: 0; font-size: 16px; color: #333333;"><strong>$stic_signatures_pdf_template</strong></p>\n<p style="margin: 5px 0 0 0; font-size: 14px; color: #888888;"><strong>Firmant:</strong> $contact_full_name$contact_user_full_name</p>\n<p style="margin: 5px 0 0 0; font-size: 14px; color: #888888;"><strong>Data de caducitat:</strong> $stic_signatures_expiration_date</p>\n</div>\n<p style="font-size: 16px; color: #555555; margin-top: 20px;">Per firmar el document, feu clic a continuació i se us redirigirà al portal de firma segura.</p>\n<p style="font-size: 16px; color: #555555; margin-top: 20px;"> </p>\n<div style="text-align: center; margin-top: 30px;"><a style="display: inline-block; padding: 12px 24px; font-size: 16px; color: #000000; background-color: #b5bc31; border-radius: 5px; text-decoration: none; font-weight: bold;" href="$sugarurl/index.php?entryPoint=sticSign&signatureId=$stic_signatures_id&targetId=$contact_id$contact_user_id">Signar el document</a></div>\n<p style="font-size: 14px; color: #aaaaaa; text-align: center; margin-top: 30px;">Si no podeu accedir al portal de firma, copieu i enganxeu l''enllaç al vostre navegador: <br /><a style="color: #b5bc31; text-decoration: none;" href="$sugarurl/index.php?entryPoint=sticSign&signatureId=$stic_signatures_id&targetId=$contact_id$contact_user_id">$sugarurl/index.php?entryPoint=sticSign&signatureId=$stic_signatures_id&targetId=$contact_id$contact_user_id</a></p>\n</div>\n</div>\n</body>\n</html>', 0, '1', 0, 'notification'),
('000005f1-2e4e-3b11-051f-68e3c9e70331', NOW(), NOW(), '1', '1', 'off', 'Exemple - Document firmat', 'Plantilla per enviar al firmant el document firmat.', '[Firma de document] Document firmat: $stic_signatures_pdf_template', 'Document firmat\n\nAdjunt a aquest correu trobareu la versió final del document que heu firmat:\n\n$stic_signatures_pdf_template\n\nFirmant: $contact_full_name$contact_user_full_name\nData de la firma: $stic_signers_signature_date\n\nAl portal de firma podreu accedir al document firmat sempre que sigui necessari.\n\nVes al portal de firma: $sugarurl/index.php?entryPoint=sticSign&signerId=$stic_signers_id', '<!DOCTYPE html>\n<html>\n<head>\n</head>\n<body>\n<p> </p>\n<div style="max-width: 600px; margin: 20px auto; background-color: #ffffff; border-radius: 8px; box-shadow: 0 4px 8px rgba(0,0,0,0.1); overflow: hidden;">\n<div style="background-color: #b5bc31; color: #000000; padding: 20px; text-align: center;">\n<h1 style="margin: 0; font-size: 24px;">Document firmat</h1>\n</div>\n<div style="padding: 20px;">\n<p style="font-size: 16px; color: #555555;">Adjunt a aquest correu trobareu la versió final del document que heu firmat:</p>\n<div style="background-color: #f9f9f9; padding: 15px; border-radius: 6px; border: 1px solid #eeeeee; margin-top: 20px;">\n<p style="margin: 0; font-size: 16px; color: #333333;"><strong>$stic_signatures_pdf_template</strong></p>\n<p style="margin: 5px 0 0 0; font-size: 14px; color: #888888;"><strong>Firmant:</strong> $contact_full_name$contact_user_full_name</p>\n<p style="margin: 5px 0 0 0; font-size: 14px; color: #888888;"><strong>Data de la firma:</strong> $stic_signers_signature_date</p>\n</div>\n<p style="font-size: 16px; color: #555555; margin-top: 20px;">Al portal de firma podreu accedir al document firmat sempre que sigui necessari.</p>\n<div style="text-align: center; margin-top: 30px;"><a style="display: inline-block; padding: 12px 24px; font-size: 16px; color: #000000; background-color: #b5bc31; border-radius: 5px; text-decoration: none; font-weight: bold;" href="$sugarurl/index.php?entryPoint=sticSign&signerId=$stic_signers_id">Ves al portal de firma</a></div>\n</div>\n</div>\n</body>\n</html>', 0, '1', 0, 'notification'),
('000005f1-2e4e-3b11-051f-68e3c9e70332', NOW(), NOW(), '1', '1', 'off', 'Exemple - Codi d''un sol ús per firmar', 'Plantilla per enviar el codi d''un sol ús al firmant abans de poder firmar.', '[Firma de document] Codi de verificació per firmar', 'Verificació de firma\n\nPer garantir la seguretat i autenticitat de la vostra firma, feu servir el codi de verificació que es mostra a continuació:\n\n$stic_signatures_pdf_template\n\n$stic_signers_otp\n\nIntroduïu aquest codi al portal de firma per continuar el procés. El codi és vàlid durant 10 minuts i només es pot fer servir una vegada.', '<!DOCTYPE html>\n<html>\n<head>\n</head>\n<body>\n<p> </p>\n<div style="max-width: 600px; margin: 20px auto; background-color: #ffffff; border-radius: 8px; box-shadow: 0 4px 8px rgba(0,0,0,0.1); overflow: hidden;">\n<div style="background-color: #b5bc31; color: #000000; padding: 20px; text-align: center;">\n<h1 style="margin: 0; font-size: 24px;">Verificació de firma</h1>\n</div>\n<div style="padding: 20px;">\n<p style="font-size: 16px; color: #555555;">Per garantir la seguretat i autenticitat de la vostra signatura, feu servir el codi de verificació que es mostra a continuació:</p>\n<div style="background-color: #f9f9f9; padding: 15px; border-radius: 6px; border: 1px solid #eeeeee; margin-top: 20px;">\n<p style="margin: 0; font-size: 16px; color: #333333;"><strong>$stic_signatures_pdf_template</strong></p>\n<div style="text-align: center; margin-top: 10px; margin-bottom: 10px;"><span style="display: inline-block; padding: 15px 30px; font-size: 28px; color: #000000; background-color: #b5bc31; border-radius: 5px; font-weight: bold; letter-spacing: 5px;">$stic_signers_otp</span></div>\n</div>\n<p style="font-size: 16px; color: #555555; margin-top: 20px;">Introduïu aquest codi al portal de firma per continuar el procés. El codi és vàlid durant 10 minuts i només es pot fer servir una vegada.</span></p>\n</div>\n</div>\n</body>\n</html>', 0, '1', 0, 'notification'),
('000005f1-2e4e-3b11-051f-68e3c9e70333', NOW(), NOW(), '1', '1', 'off', 'Exemple - Codi d''un sol ús per firmar (SMS)', 'Plantilla per enviar via SMS el codi d''un sol ús al firmant abans de poder firmar.', '[Firma de document] Codi de verificació per firmar', '$contact_first_name$contact_user_first_name, aquest és el vostre codi per firmar: $stic_signers_otp. És vàlid durant 10 minuts.', '<!DOCTYPE html>\n<html>\n<head>\n</head>\n<body>\n\n</body>\n</html>', 0, '1', 1, 'system'),
('00000b6d-9a8d-37c0-684e-6931622133d8', NOW(), NOW(), '1', '1', 'off', 'Exemple - Notificació de la renovació de la pòlissa d’assegurances', NULL, 'Renovació de la pòlissa d’assegurança de voluntariat', NULL, '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n</head>\r\n<body>\r\n<p data-start=\"262\" data-end=\"301\">La <strong>pòlissa d’assegurança de voluntariat</strong> de $contact_name caducarà aviat i cal renovar-la per mantenir la cobertura activa.</p>\r\n</body>\r\n</html>', 0, '1', 0, 'email'),
('00000258-e3da-390c-e722-693162f2060f', NOW(), NOW(), '1', '1', 'off', 'Exemple - Notificació de la renovació del certificat de delictes', NULL, 'Renovació del Certificat de Delictes', NULL, '<!DOCTYPE html>\n<html>\n<head>\n</head>\n<body>\n<p data-start=\"131\" data-end=\"362\">El <strong data-start=\"134\" data-end=\"160\">Certificat de Delictes</strong> de $contact_name caducarà aviat i cal renovar-lo perquè pugui continuar desenvolupant la seva activitat a la nostra organització. Cal, doncs, iniciar el procés de renovació com més aviat millor.</p>\n</body>\n</html>', 0, '1', 0, 'email'),
('d3c1d5b7-f8d2-4df4-9f6b-2c63aa6b8e41', NOW(), NOW(), '1', '1', NULL, 'Exemple - Notificació - Oferta amb tancament vençut sense estat tancada', 'Plantilla per notificar al responsable que l''oferta té la data de tancament de candidatures d''ahir i no està en estat tancada o similar.', 'Revisar oferta laboral: tancament de candidatures vençut - $stic_job_offers_name', 'Benvolgut/da $stic_job_offers_assigned_user_name,\r\n\r\nL''oferta laboral $stic_job_offers_name té la data de tancament de candidatures vençuda (ahir) i actualment està en estat $stic_job_offers_status.\r\n\r\nSi us plau, revisa l''oferta i actualitza''n l''estat si correspon: $sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id', '<p>Benvolgut/da $stic_job_offers_assigned_user_name,</p>\n<p>L''oferta laboral <strong>$stic_job_offers_name</strong> té la data de tancament de candidatures vençuda (ahir) i actualment està en estat <strong>$stic_job_offers_status</strong>.</p>\n<p>Si us plau, <a href="$sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id">revisa l''oferta</a> i actualitza''n l''estat si correspon.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0001', NOW(), NOW(), '1', '1', NULL, 'Exemple - Candidatura acceptada - Usuari assignat ', 'Notifica a l''usuari assignat quan una candidatura passa a Acceptada, amb enllaç al CRM.', 'Candidatura acceptada: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $stic_job_applications_assigned_user_name,\r\n\r\nLa candidatura de $stic_job_applications_stic_job_applications_contacts_name per a l''oferta $stic_job_applications_stic_job_applications_stic_job_offers_name ha canviat a estat Acceptada.\r\n\r\nLa pots revisar al CRM: $sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id', '<p>Benvolgut/da $stic_job_applications_assigned_user_name,</p><p>La candidatura de <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> per a l''oferta <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> ha canviat a estat <strong>Acceptada</strong>.</p><p>La pots revisar al CRM: <a href="$sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id">Obrir candidatura al CRM</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0002', NOW(), NOW(), '1', '1', NULL, 'Exemple - Candidatura acceptada - Candidat ', 'Notifica al candidat quan la seva candidatura passa a Acceptada, amb enllaç a l''àrea privada.', 'La teva candidatura ha estat acceptada: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $stic_job_applications_stic_job_applications_contacts_name:\r\n\r\nEns complau informar-te que la teva candidatura per a l''oferta $stic_job_applications_stic_job_applications_stic_job_offers_name ha passat a estat Acceptada.\r\n\r\nPots consultar-ne el detall a la teva àrea privada: $portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id', '<p>Benvolgut/da $stic_job_applications_stic_job_applications_contacts_name:</p><p>Ens complau informar-te que la teva candidatura per a l''oferta <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> ha passat a estat <strong>Acceptada</strong>.</p><p>Pots consultar-ne el detall a la teva àrea privada: <a href="$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id">Accedir a l''àrea privada</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0003', NOW(), NOW(), '1', '1', NULL, 'Exemple - Candidatura acceptada - Organització ', 'Notifica a l''organització quan una candidatura passa a Acceptada, amb enllaç a l''àrea privada.', 'Candidatura acceptada a l''oferta: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $stic_job_applications_account,\r\n\r\nLa candidatura de $stic_job_applications_stic_job_applications_contacts_name per a l''oferta $stic_job_applications_stic_job_applications_stic_job_offers_name ha passat a estat Acceptada.\r\n\r\nHo pots veure a l''àrea privada: $portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id', '<p>Benvolgut/da $stic_job_applications_account,</p><p>La candidatura de <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> per a l''oferta <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> ha passat a estat <strong>Acceptada</strong>.</p><p>Ho pots veure a l''àrea privada: <a href="$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id">Accedir a l''àrea privada</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0010', NOW(), NOW(), '1', '1', NULL, 'Exemple - Candidatura rebutjada/tancada - Usuari assignat', 'Notifica a l usuari l estat de descarte.', 'Candidatura rebutjada o tancada: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $stic_job_applications_assigned_user_name,\n\nT informem que s ha actualitzat l estat de la candidatura de $stic_job_applications_stic_job_applications_contacts_name per a la posició $stic_job_applications_stic_job_applications_stic_job_offers_name.\n\nL estat actual és: Candidatura descartada / Procés tancat.', '<p>Benvolgut/da <strong>$stic_job_applications_assigned_user_name</strong>,</p><p>T informem que s ha actualitzat l estat de la candidatura de <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> per a la posició <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong>.</p><p>L estat actual és: <strong>Candidatura descartada / Procés tancat.</strong></p><p>Pots revisar el detall al CRM: <a href=\"$sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id\">Obrir candidatura al CRM</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0011', NOW(), NOW(), '1', '1', NULL, 'Exemple - Candidatura rebutjada/tancada - Candidat', 'Notifica al candidat el descarte.', 'Actualització de la teva candidatura: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $stic_job_applications_stic_job_applications_contacts_name:\n\nMoltes gràcies per l interès en l oferta de $stic_job_applications_stic_job_applications_stic_job_offers_name.\n\nLamentem comunicar-te que en aquesta ocasió hem decidit avançar amb altres candidatures que s ajusten més als requisits actuals.', '<p>Benvolgut/da <strong>$stic_job_applications_stic_job_applications_contacts_name</strong>:</p><p>Moltes gràcies per l interès que has mostrat en la nostra oferta de <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong>.</p><p>Després d una valoració detallada, lamentem comunicar-te que en aquesta ocasió hem decidit avançar amb altres candidatures que s ajusten més als requisits actuals.</p><p>Pots consultar l estat a la teva àrea privada: <a href=\"$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id\">Accedir a l àrea privada</a>.</p><p>Et desitgem molt d èxit. Atentament, $stic_job_applications_account</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0012', NOW(), NOW(), '1', '1', NULL, 'Exemple - Candidatura rebutjada/tancada - Organització', 'Notifica al compte el descarte.', 'Candidatura rebutjada o tancada a l oferta: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $stic_job_applications_account:\n\nLi comuniquem que la candidatura de $stic_job_applications_stic_job_applications_contacts_name per a la vacant de $stic_job_applications_stic_job_applications_stic_job_offers_name ha finalitzat la seva participació.', '<p>Benvolgut/da <strong>$stic_job_applications_account</strong>:</p><p>Li comuniquem que la candidatura de <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> per a la vacant de <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> ha finalizado su participación en el proceso.</p><p>Pot realitzar el seguiment a la seva àrea de client: <a href=\"$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id\">Accedir a l àrea privada</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0004', NOW(), NOW(), '1', '1', NULL, 'Exemple - Candidatura rebutjada/tancada - Usuari assignat', 'Notifica a l''usuari assignat quan una candidatura passa a Rebutjada o tancada, amb enllaç al CRM.', 'Candidatura rebutjada o tancada: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $stic_job_applications_assigned_user_name,\n\nLa candidatura de $stic_job_applications_stic_job_applications_contacts_name per a l''oferta $stic_job_applications_stic_job_applications_stic_job_offers_name ha canviat a estat Rebutjada o tancada.\n\nPots accedir al detall a: $sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id', '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n</head>\r\n<body>\r\n<p>Benvolgut/da <strong>$stic_job_applications_assigned_user_name</strong>,</p>\r\n<p>T''informem que s''ha actualitzat l''estat de la candidatura de <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> per a la posició <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong>.</p>\r\n<p>El nou estat és: <strong>Candidatura descartada / Procés tancat.</strong></p>\r\n<p>Pots revisar l''historial o els motius del descart directament al CRM mitjançant l''enllaç següent:</p>\r\n<p><a href="$sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id">Obrir candidatura al CRM</a></p>\r\n</body>\r\n</html>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0007', NOW(), NOW(), '1', '1', NULL, 'Exemple - Candidatura altres estats - Usuari assignat ', 'Notifica a l''usuari assignat quan una candidatura passa a altres estats, amb enllaç al CRM.', 'Canvi d''estat de candidatura: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $stic_job_applications_assigned_user_name,\r\n\r\nLa candidatura de $stic_job_applications_stic_job_applications_contacts_name per a l''oferta $stic_job_applications_stic_job_applications_stic_job_offers_name ha canviat a estat $stic_job_applications_status.\r\n\r\nPots accedir al detall a: $sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id', '<p>Benvolgut/da $stic_job_applications_assigned_user_name,</p><p>La candidatura de <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> per a l''oferta <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> ha canviat a estat <strong>$stic_job_applications_status</strong>.</p><p>Pots accedir al detall a: <a href="$sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id">Obrir candidatura al CRM</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0008', NOW(), NOW(), '1', '1', NULL, 'Exemple - Candidatura altres estats - Candidat ', 'Notifica al candidat quan la seva candidatura passa a altres estats, amb enllaç a l''àrea privada.', 'Canvi d''estat de la teva candidatura: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $stic_job_applications_stic_job_applications_contacts_name:\r\n\r\nLa teva candidatura per a l''oferta $stic_job_applications_stic_job_applications_stic_job_offers_name ha canviat a estat $stic_job_applications_status.\r\n\r\nPots consultar-ne el detall a la teva àrea privada: $portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id', '<p>Benvolgut/da $stic_job_applications_stic_job_applications_contacts_name:</p><p>La teva candidatura per a l''oferta <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> ha canviat a estat <strong>$stic_job_applications_status</strong>.</p><p>Pots consultar-ne el detall a la teva àrea privada: <a href="$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id">Accedir a l''àrea privada</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0009', NOW(), NOW(), '1', '1', NULL, 'Exemple - Candidatura altres estats - Organització ', 'Notifica a l''organització quan una candidatura passa a altres estats, amb enllaç a l''àrea privada.', 'Canvi d''estat de candidatura a l''oferta: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $stic_job_applications_account,\r\n\r\nLa candidatura de $stic_job_applications_stic_job_applications_contacts_name per a l''oferta $stic_job_applications_stic_job_applications_stic_job_offers_name ha canviat a estat $stic_job_applications_status.\r\n\r\nHo pots veure a l''àrea privada: $portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id', '<p>Benvolgut/da $stic_job_applications_account,</p><p>La candidatura de <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> per a l''oferta <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> ha canviat a estat <strong>$stic_job_applications_status</strong>.</p><p>Ho pots veure a l''àrea privada: <a href="$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id">Accedir a l''àrea privada</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0010', NOW(), NOW(), '1', '1', NULL, 'Exemple - Oferta canvi d''estat - Usuari assignat ', 'Notifica a l''usuari assignat quan canvia l''estat d''una oferta, amb enllaç al CRM.', 'Canvi d''estat de l''oferta: $stic_job_offers_name', 'Benvolgut/da $stic_job_offers_assigned_user_name,\r\n\r\nL''oferta $stic_job_offers_name ha canviat a estat $stic_job_offers_status.\r\n\r\nPots accedir al detall a: $sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id', '<p>Benvolgut/da $stic_job_offers_assigned_user_name,</p><p>L''oferta <strong>$stic_job_offers_name</strong> ha canviat a estat <strong>$stic_job_offers_status</strong>.</p><p>Pots accedir al detall a: <a href="$sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id">Obrir oferta al CRM</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0011', NOW(), NOW(), '1', '1', NULL, 'Exemple - Oferta canvi d''estat - Candidats ', 'Notifica als candidats un canvi d''estat de l''oferta, amb enllaç a l''àrea privada.', 'Actualització de l''oferta: $stic_job_offers_name', 'Benvolgut/da,\r\n\r\nL''oferta $stic_job_offers_name ha canviat d''estat a $stic_job_offers_status.\r\n\r\nPots consultar l''oferta a l''àrea privada: $portal_address/?internalpage=single_stic_job_offers&action=detail&id=$stic_job_offers_id', '<p>Benvolgut/da:</p><p>L''oferta <strong>$stic_job_offers_name</strong> ha canviat d''estat a <strong>$stic_job_offers_status</strong>.</p><p>Pots consultar l''oferta a l''àrea privada: <a href="$portal_address/?internalpage=single_stic_job_offers&action=detail&id=$stic_job_offers_id">Veure oferta a l''àrea privada</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0012', NOW(), NOW(), '1', '1', NULL, 'Exemple - Oferta canvi d''estat - Organització ', 'Notifica a l''organització un canvi d''estat de l''oferta, amb enllaç a l''àrea privada.', 'Canvi d''estat de l''oferta: $stic_job_offers_name', 'Benvolgut/da $stic_job_offers_stic_job_offers_accounts_name,\r\n\r\nL''oferta $stic_job_offers_name ha canviat d''estat a $stic_job_offers_status.\r\n\r\nPots revisar-la a l''àrea privada: $portal_address/?internalpage=single_stic_job_offers&action=detail&id=$stic_job_offers_id', '<p>Benvolgut/da $stic_job_offers_stic_job_offers_accounts_name,</p><p>L''oferta <strong>$stic_job_offers_name</strong> ha canviat d''estat a <strong>$stic_job_offers_status</strong>.</p><p>Pots revisar-la a l''àrea privada: <a href="$portal_address/?internalpage=single_stic_job_offers&action=detail&id=$stic_job_offers_id">Veure oferta a l''àrea privada</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0013', NOW(), NOW(), '1', '1', NULL, 'Exemple - Oferta canvi d''estat - Interlocutor', 'Notifica a l''interlocutor un canvi d''estat de l''oferta, amb enllaç al CRM.', 'Actualització de l''oferta: $stic_job_offers_name', 'Benvolgut/da $stic_job_offers_interlocutor,\r\n\r\nL''oferta $stic_job_offers_name ha canviat d''estat a $stic_job_offers_status.\r\n\r\nPots revisar-la al CRM: $sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id', '<p>Benvolgut/da $stic_job_offers_interlocutor,</p><p>L''oferta <strong>$stic_job_offers_name</strong> ha canviat d''estat a <strong>$stic_job_offers_status</strong>.</p><p>Pots revisar-la al CRM: <a href="$sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id">Obrir oferta al CRM</a>.</p>', 0, '1', 0, 'notification'),
('6e6f5a91-2cb9-4f42-bf26-0a13b2f1c101', NOW(), NOW(), '1', '1', NULL, 'Exemple - Àrea Privada - Credencials d''accés (Persona)', 'Plantilla inicial per enviar les credencials de l''Àrea Privada a Personas quan s''activa l''accés', 'Les teves credencials d''accés a l''Àrea Privada', 'Hola $contacts_name,\r\n\r\nJa tens habilitat l''accés a l''Àrea Privada.\r\n\r\nUsuari: $contacts_stic_pa_username_c\r\nContrasenya: $contacts_stic_pa_password_c\r\n\r\nAccedeix des de: $portal_address\r\n\r\nSi no has sol·licitat aquest accés, contacta amb l''entitat.', '<p>Hola $contacts_name,</p><p>Ja tens habilitat l''accés a l''Àrea Privada.</p><p><strong>Usuari:</strong> $contacts_stic_pa_username_c<br><strong>Contrasenya:</strong> $contacts_stic_pa_password_c</p><p>Accedeix des de: <a href="$portal_address">$portal_address</a></p><p>Si no has sol·licitat aquest accés, contacta amb l''entitat.</p>', 0, '1', 0, 'notification'),
('6e6f5a91-2cb9-4f42-bf26-0a13b2f1c102', NOW(), NOW(), '1', '1', NULL, 'Exemple - Àrea Privada - Credencials d''accés (Compte)', 'Plantilla inicial per enviar les credencials de l''Àrea Privada a Comptes quan s''activa l''accés', 'Credencials d''accés a l''Àrea Privada', 'Hola $accounts_name,\r\n\r\nJa tens habilitat l''accés a l''Àrea Privada.\r\n\r\nUsuari: $accounts_stic_pa_username_c\r\nContrasenya: $accounts_stic_pa_password_c\r\n\r\nAccedeix des de: $portal_address\r\n\r\nSi no has sol·licitat aquest accés, contacta amb l''entitat.', '<p>Hola $accounts_name,</p><p>Ja tens habilitat l''accés a l''Àrea Privada.</p><p><strong>Usuari:</strong> $accounts_stic_pa_username_c<br><strong>Contrasenya:</strong> $accounts_stic_pa_password_c</p><p>Accedeix des de: <a href="$portal_address">$portal_address</a></p><p>Si no has sol·licitat aquest accés, contacta amb l''entitat.</p>', 0, '1', 0, 'notification'),
('7a9f8f3a-2d1f-4a40-9dd6-7c6f9e1b7001', '2026-03-31 17:31:01', '2026-03-31 17:31:01', '1', '1', NULL, 'Exemple - Candidatura presentada - Usuari assignat', 'Notifica a l''usuari assignat quan es presenta una nova candidatura, amb enllaç al CRM.', 'Nova candidatura rebuda: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $stic_job_applications_assigned_user_name,\r\n\r\nS''ha presentat una nova candidatura de $stic_job_applications_stic_job_applications_contacts_name per a l''oferta $stic_job_applications_stic_job_applications_stic_job_offers_name.\r\n\r\nLa pots revisar al CRM: $sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id', '<p>Benvolgut/da $stic_job_applications_assigned_user_name,</p><p>S''ha presentat una nova candidatura de <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> per a l''oferta <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong>.</p><p>La pots revisar al CRM: <a href=\"$sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id\">Obrir candidatura al CRM</a>.</p>', 0, '1', 0, 'notification'),
('7a9f8f3a-2d1f-4a40-9dd6-7c6f9e1b7002', '2026-03-31 17:31:01', '2026-03-31 17:31:01', '1', '1', NULL, 'Exemple - Nou missatge en conversa - Usuari assignat', 'Notifica a l''usuari assignat quan arriba un nou missatge en una conversa.', 'Nou missatge rebut', 'Benvolgut/da $stic_messages_assigned_user_name,\r\n\r\nS''ha rebut un nou missatge en una conversa del portal.\r\n\r\nMissatge:\r\n$stic_messages_message\r\n\r\nEl pots revisar al CRM: $sugarurl/index.php?module=stic_Messages&action=DetailView&record=$stic_messages_id', '<p>Benvolgut/da $stic_messages_assigned_user_name,</p><p>S''ha rebut un nou missatge en una conversa del portal.</p><p><strong>Missatge:</strong><br>$stic_messages_message</p><p>El pots revisar al CRM: <a href=\"$sugarurl/index.php?module=stic_Messages&action=DetailView&record=$stic_messages_id\">Obrir missatge al CRM</a>.</p>', 0, '1', 0, 'notification'),
('3c0a5f6e-1111-4f8a-9a11-3b1b7c2a0101', NOW(), NOW(), '1', '1', NULL, 'Exemple - Nova oferta laboral - Usuari assignat', 'Notifica a l''usuari assignat la creació d''una nova oferta laboral.', 'Nova oferta creada: $stic_job_offers_name', 'Benvolgut/da $stic_job_offers_assigned_user_name,\r\n\r\nS''ha creat una nova oferta laboral: $stic_job_offers_name.\r\n\r\nLa pots revisar al CRM: $sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id', '<p>Benvolgut/da $stic_job_offers_assigned_user_name,</p><p>S''ha creat una nova oferta laboral: <strong>$stic_job_offers_name</strong>.</p><p>La pots revisar al CRM: <a href="$sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id">Obrir oferta al CRM</a>.</p>', 0, '1', 0, 'notification'),
('3c0a5f6e-1111-4f8a-9a11-3b1b7c2a0102', NOW(), NOW(), '1', '1', NULL, 'Exemple - Nova oferta laboral - Organització', 'Notifica a l''organització la creació d''una nova oferta laboral.', 'Nova oferta creada: $stic_job_offers_name', 'Benvolgut/da $stic_job_offers_stic_job_offers_accounts_name,\r\n\r\nS''ha creat una nova oferta laboral: $stic_job_offers_name.\r\n\r\nLa pots revisar al CRM: $sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id', '<p>Benvolgut/da $stic_job_offers_stic_job_offers_accounts_name,</p><p>S''ha creat una nova oferta laboral: <strong>$stic_job_offers_name</strong>.</p><p>La pots revisar al CRM: <a href="$sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id">Obrir oferta al CRM</a>.</p>', 0, '1', 0, 'notification'),
('3c0a5f6e-1111-4f8a-9a11-3b1b7c2a0103', NOW(), NOW(), '1', '1', NULL, 'Exemple - Nova oferta laboral - Interlocutor', 'Notifica a l''interlocutor la creació d''una nova oferta laboral.', 'Nova oferta creada: $stic_job_offers_name', 'Benvolgut/da $stic_job_offers_interlocutor,\r\n\r\nS''ha creat una nova oferta laboral: $stic_job_offers_name.\r\n\r\nLa pots revisar al CRM: $sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id', '<p>Benvolgut/da $stic_job_offers_interlocutor,</p><p>S''ha creat una nova oferta laboral: <strong>$stic_job_offers_name</strong>.</p><p>La pots revisar al CRM: <a href="$sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id">Obrir oferta al CRM</a>.</p>', 0, '1', 0, 'notification');
INSERT INTO `email_templates` (`id`, `date_entered`, `date_modified`, `modified_user_id`, `created_by`, `published`, `name`, `description`, `subject`, `body`, `body_html`, `deleted`, `assigned_user_id`, `text_only`, `type`) VALUES
('14f18ded-378d-ab84-3237-5e830d4e874d', NOW(), NOW(), '1', '1', 'off', 'Cas actualitzat (Usuaris)', 'Plantilla per informar un usuari del CRM quan s''actualitza un cas que té assignat.', 'Actualització de: $acase_name (# $acase_case_number)', 'Hola, $user_first_name $user_last_name:\n\nHi ha hagut una actualització del cas $acase_name (# $acase_case_number) el $aop_case_updates_date_entered.\n\n$contact_first_name $contact_last_name diu:\n\n	$aop_case_updates_description\n\nPots revisar el cas a: $sugarurl/index.php?module=Cases&action=DetailView&record=$acase_id', '<p>Hola, $user_first_name $user_last_name:</p>\n	<p> </p>\n <p>Hi ha hagut una actualizació del cas $acase_name (# $acase_case_number) el $aop_case_updates_date_entered.</p>\n <p><strong>$contact_first_name $contact_last_name diu:</strong></p>\n <p style="padding-left:30px;">$aop_case_updates_description</p>\n <p>Pots revisar el cas a: $sugarurl/index.php?module=Cases&action=DetailView&record=$acase_id</p>', 0, NULL, NULL, 'system'),
('267275d8-959c-6aed-8754-5e830d07fedf', NOW(), NOW(), '1', '1', 'off', 'Invitació a esdeveniment', 'Plantilla d''invitació a un esdeveniment.', 'Invitació a $fp_events_name', 'Benvolgut/da $contact_name:\nHas estat convidat/da a $fp_events_name del $fp_events_date_start al $fp_events_date_end.\n$fp_events_description\nCordialment,\n', '\n<p>Benvolgut/da $contact_name:</p>\n<p>Has estat convidat/da a $fp_events_name del $fp_events_date_start al $fp_events_date_end.</p>\n<p>$fp_events_description</p>\n<p>Si vols acceptar aquesta invitació fes clic a Accepto.</p>\n<p> $fp_events_link o $fp_events_link_declined</p>\n<p>Cordialment,</p>\n', 0, NULL, NULL, 'system'),
('483e1c3b-51dc-b5ab-e220-5e830d52596a', NOW(), NOW(), '1', '1', 'off', 'Confirmació d''alta voluntària', 'Plantilla per confirmar l''alta voluntària d''una persona.', 'Confirmació d''alta voluntària', 'Hola, $contact_first_name $contact_last_name:\nSi us plau, confirma la teva alta voluntària fent clic a l''enllaç següent: $sugarurl/index.php?entryPoint=ConfirmOptIn&from=$emailaddress_email_address', '<p>Hola, $contact_first_name $contact_last_name:</p>\n <p>Si us plau, confirma la teva alta voluntària fent clic a l''enllaç següent:\n <a href="$sugarurl/index.php?entryPoint=ConfirmOptIn&from=$emailaddress_confirm_opt_in_token">Alta voluntària</a></p>\n', 0, NULL, NULL, 'system'),
('b4477938-f3c4-bef6-292c-5e830dee6ceb', NOW(), NOW(), '1', '1', 'off', 'Contrasenya generada pel sistema', 'Plantilla per notificar una contrasenya a un usuari.', 'Informació del nou compte', 'Aquí teniu el vostre nom d''usuari i una contrasenya provisional:\nNom d''usuari: $contact_user_user_name\nContrasenya: $contact_user_user_hash\n\n$config_site_url\n\nQuan accediu al sistema amb aquesta contrasenya pot ser que se us demani que la canvieu per una de nova.', '<div><table width="550"><tbody><tr><td><p>Aquí teniu el vostre nom d''usuari i una contrasenya provisional:</p>\n <p>Nom d''usuari: $contact_user_user_name </p>\n <p>Contrasenya: $contact_user_user_hash </p>\n <p>$config_site_url</p>\n <p>Quan accediu al sistema amb aquesta contrasenya pot ser que se us demani que la canvieu per una de nova.</p></td></tr></tbody></table></div>', 0, NULL, 0, 'system'),
('bc4c87c3-febd-73d5-cf73-5e830dd3bac0', NOW(), NOW(), '1', '1', 'off', 'Contrasenya oblidada', 'Plantilla per regenerar la contrasenya d''accés al CRM.', 'Restableix la teva contrasenya', 'El $contact_user_pwd_last_changed has demanat poder restablir la teva contrasenya.\n\nFes clic al següent enllaç per restablir-la:\n\n$contact_user_link_guid', '<div><table width="550"><tbody><tr><td><p>El $contact_user_pwd_last_changed has demanat poder restablir la teva contrasenya. </p><p>Fes clic al següent enllaç per restablir-la:</p><p> $contact_user_link_guid </p>  </td>         </tr><tr><td></td>         </tr></tbody></table></div>', 0, NULL, 0, 'system'),
('c4440a38-10b9-ef63-0e40-5e830d1c293d', NOW(), NOW(), '1', '1', 'off', 'Doble factor d''autenticació', 'Plantilla per enviar un codi de doble factor d''autenticació.', 'Codi de doble factor d''autenticació', 'El codi de doble factor d''autenticació és $code.', '<div><table width="550"><tbody><tr><td><p>El codi de doble factor d''autenticació és <b>$code</b>.</p></td></tr></tbody></table></div>', 0, NULL, 0, 'system'),
('c6c4093f-0a1a-30d8-5e33-5e830d6ddd51', NOW(), NOW(), '1', '1', 'off', 'Cas actualitzat (Persones)', 'Plantilla per enviar a una persona quan s''actualitza un cas amb el qual està relacionada', 'Actualització del cas: $acase_name [$acase_case_number]', 'Hola, $contact_first_name $contact_last_name:\n\nHi ha hagut una actualització del cas $acase_name (# $acase_case_number) el $aop_case_updates_date_entered.\n\n$contact_first_name $contact_last_name diu:\n\n	aop_case_updates_description', '<p>Hola, $contact_first_name $contact_last_name:</p>\n <p> </p>\n <p>Hi ha hagut una actualització del cas $acase_name (# $acase_case_number) el $aop_case_updates_date_entered:</p>\n <p><strong>$user_first_name $user_last_name diu:</strong></p>\n <p style="padding-left:30px;">$aop_case_updates_description</p>', 0, NULL, NULL, 'system'),
('e61c85c2-e6cb-6dda-3760-5e830d31fbdc', NOW(), NOW(), '1', '1', 'off', 'Cas tancat', 'Plantilla per informar una persona que s''ha tancat un cas amb el qual estava relacionada.', 'Cas tancat: $acase_name [$acase_case_number]', 'Hola, $contact_first_name $contact_last_name:\n\nEl cas $acase_name (# $acase_case_number) s''ha tancat el $acase_date_entered.\n\n	Estat:	$acase_status\n	Codi:	$acase_case_number\n	Resolució:	$acase_resolution', '<p>Hola, $contact_first_name $contact_last_name:</p>\n <p>El cas $acase_name (# $acase_case_number) s''ha tancat el $acase_date_entered</p>\n <table border="0"><tbody><tr><td>Estat</td><td>$acase_status</td></tr><tr><td>Codi</td><td>$acase_case_number</td></tr><tr><td>Resolució</td><td>$acase_resolution</td></tr></tbody></table>', 0, NULL, NULL, 'system'),
('e9e00ea2-ac1b-a635-9671-5e830d66a582', NOW(), NOW(), '1', '1', 'off', 'Cas creat', 'Plantilla per enviar a una persona quan aquesta obre un cas.', 'Nou cas: $acase_name [$acase_case_number]', 'Hola, $contact_first_name $contact_last_name:\n\nHem rebut el teu cas $acase_name (# $acase_case_number) el $acase_date_entered.\n\n	Estat:	$acase_status\n	Codi:	$acase_case_number\n	Descripció:	$acase_description', '<p>Hola, $contact_first_name $contact_last_name:</p>\n <p>Hem rebut el teu cas $acase_name (# $acase_case_number) el $acase_date_entered</p>\n <table border="0"><tbody><tr><td>Estat</td><td>$acase_status</td></tr><tr><td>Codi</td><td>$acase_case_number</td></tr><tr><td>Descripció</td><td>$acase_description</td></tr></tbody></table>', 0, NULL, NULL, 'system'),
('ed9867a2-1f56-b684-4bc6-5e830d215b5d', NOW(), NOW(), '1', '1', 'off', 'Compte creat', 'Plantilla per informar una persona que se li ha creat un compte al portal de casos.', 'Compte creat al portal de suport', 'Hola, $contact_name:\n\n Ja disposes d''un compte per accedir a $portal_address.\n\n Pots connectar-t''hi fent servir la teva adreça electrònica i la contrasenya $joomla_pass.', '<p>Hola, $contact_name:</p>\n <p>Ja disposes d''un compte per accedir a <a href="$portal_address">$portal_address</a>.</p>\n	<p>Pots connectar-t''hi fent servir la teva adreça electrònica i la contrasenya $joomla_pass.</p>', 0, NULL, NULL, 'system');
